06_ConstructBinaryTree1. 题目 重建二叉树输入某二叉树前序和中序遍历的结果，请重建出该二叉树。假设输入的前序遍历和中序遍历的结果中都不含重复的数字。例如输入前序遍历序列 {1, 2, 4, 7, 3, 5, 6, 8}和中序遍历序列 {4, 7, 2, 1, 5, 3, 8, 6}，则重建出下图所示的二叉树并输出它的头结点。二叉树结点的定义如下：123456struct BinaryTreeNode&#123; int m_nValue; BinaryTreeNode* m_pLeft; BinaryTreeNode* m_pRight;&#125;; 1234567 1 / \ 2 3 / / \4 5 6\ / 7 8 2. 代码 剑指offer // 06_ConstructBinaryTree.cpp// chenyu// 2019_08_04// 输入某二叉树的前序遍历和中序遍历的结果，重建出该二叉树。// 假设输入的前序和中序遍历的结构中都不含重复数字。// 比如前 &#123;1, 2, 4, 7, 3, 5, 6, 8&#125;// 比如中 &#123;4, 7, 2, 1, 5, 3, 8, 6&#125;#include &quot;Utilities\BinaryTree.h&quot;#include &lt;cstdio&gt;#include &lt;stdexcept&gt;BinaryTreeNode* ConstructCore(int* startPreorder, int* endPreorder, int* startInorder, int* endInorder);BinaryTreeNode* Construct(int* preorder, int* inorder, int length)&#123; if(preorder == nullptr || inorder == nullptr || length &lt;=0) return nullptr; return ConstructCore(preorder, preorder + length - 1, inorder, inorder + length -1); &#125;BinaryTreeNode* ConstructCore(int* startPreorder, int* endPreorder, int* startInorder, int* endInorder)&#123; // preorder[0] 为 tree root 的值 int rootValue = startPreorder[0]; BinaryTreeNode* root = new BinaryTreeNode(); root-&gt;m_nValue = rootValue; root-&gt;m_pLeft = root-&gt;m_pRight = nullptr; if(startPreorder == endPreorder) &#123; if(startInorder == endInorder &amp;&amp; *startPreorder == *startInorder) return root; else &#123; // 在C++标准库中，只能默认初始化 //throw std::exception(&quot;Invalid input.&quot;); // 通用异常类，只报告异常发生，不提供任何额外信息 throw std::runtime_error(&quot;
Invalid input.
&quot;); // C++ primer 异常处理 &#125; &#125; // 中序遍历找到根结点的值 int* rootInorder = startInorder; while(rootInorder &lt;= endInorder &amp;&amp; *rootInorder != rootValue) ++rootInorder; if(rootInorder == endInorder &amp;&amp; *rootInorder != rootValue) throw std::runtime_error(&quot;Invalid input.&quot;); int leftLength = rootInorder - startInorder; int* leftPreorderEnd = startPreorder + leftLength; if(leftLength &gt; 0) &#123; // 构建左子树 root-&gt;m_pLeft = ConstructCore(startPreorder + 1, leftPreorderEnd, startInorder, rootInorder - 1); &#125; if(leftLength &lt; endPreorder - startPreorder) &#123; // 构建右子树 root-&gt;m_pRight = ConstructCore(leftPreorderEnd + 1, endPreorder, rootInorder + 1, endInorder); &#125; return root; // 如果没有 return root 的话，那么叶结点的根及根的根就不会返回&#125;/************ test ***********/void Test(char* testname, int* preorder, int* inorder, int length)&#123; if(testname != nullptr) printf(&quot;%s begins:
&quot;, testname); printf(&quot;The preorder sequence is: &quot;); for(int i = 0; i &lt; length; ++i) printf(&quot;%d &quot;, preorder[i]); printf(&quot;
The inorder sequence is: &quot;); for(int i = 0; i &lt; length; ++i) printf(&quot;%d &quot;, inorder[i]); try &#123; BinaryTreeNode* root = Construct(preorder, inorder, length); PrintTree(root); DestroyTree(root); &#125; //catch(const std::exception&amp; e) catch(std::runtime_error err) // 捕捉 runtime_error 异常 &#123; printf(err.what()); // 每个异常类都定义了 what 的成员函数，无参，返回值是初始化内容 &#125;&#125;// 普通二叉树（完全二叉树）// 1// / // 2 3 // / \ / // 4 5 6 7void Test1()&#123; const int length = 7; int preorder[length] = &#123;1, 2, 4, 5, 3, 6, 7&#125;; int inorder[length] = &#123;4, 2, 5, 1, 6, 3, 7&#125;; Test(&quot;Test1&quot;, preorder, inorder, length);&#125;// 普通二叉树（不完全二叉树）// 1// / // 2 3 // / / // 4 5 6// \ /// 7 8void Test2()&#123; const int length = 8; int preorder[length] = &#123;1, 2, 4, 7, 3, 5, 6, 8&#125;; int inorder[length] = &#123;4, 7, 2, 1, 5, 3, 8, 6&#125;; Test(&quot;Test2&quot;, preorder, inorder, length);&#125;// 特殊二叉树（所有结点都没有右子结点的二叉树）// 1// / // 2 // / // 3 // /// 4// /// 5void Test3()&#123; const int length = 5; int preorder[length] = &#123;1, 2, 3, 4, 5&#125;; int inorder[length] = &#123;5, 4, 3, 2, 1&#125;; Test(&quot;Test3&quot;, preorder, inorder, length);&#125;// 特殊二叉树（所有结点都没有左子结点的二叉树）// 1// \ // 2 // \ // 3 // // 4// // 5void Test4()&#123; const int length = 5; int preorder[length] = &#123;1, 2, 3, 4, 5&#125;; int inorder[length] = &#123;1, 2, 3, 4, 5&#125;; Test(&quot;Test4&quot;, preorder, inorder, length);&#125;// 特殊二叉树（只有一个结点的二叉树）void Test5()&#123; const int length = 1; int preorder[length] = &#123;1&#125;; int inorder[length] = &#123;1&#125;; Test(&quot;Test5&quot;, preorder, inorder, length);&#125;// 特殊输入测试（二叉树根节点指针为 nullptr）void Test6()&#123; Test(&quot;Test6&quot;, nullptr, nullptr, 0);&#125;// 特殊输入测试（输入的前序遍历序列和中序遍历序列不匹配）// 前面完全二叉树的不匹配输入void Test7()&#123; const int length = 7; int preorder[length] = &#123;1, 2, 4, 5, 3, 6, 7&#125;; int inorder[length] = &#123;4, 2, 8, 1, 6, 3, 7&#125;; Test(&quot;Test7: for unmatched input&quot;, preorder, inorder, length);&#125;int main()&#123; Test1(); Test2(); Test3(); Test4(); Test5(); Test6(); Test7(); return 0; &#125; output123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123PS E:\Buffer\C++_code\CondingInterview_cy&gt; .\06_ConstructBinaryTree.exeTest1 begins:The preorder sequence is: 1 2 4 5 3 6 7The inorder sequence is: 4 2 5 1 6 3 7 value of this node is: 1value of its left child is: 2.value of its right child is: 3.value of this node is: 2value of its left child is: 4.value of its right child is: 5.value of this node is: 4left child is nullptr.right child is nullptr.value of this node is: 5left child is nullptr.right child is nullptr.value of this node is: 3value of its left child is: 6.value of its right child is: 7.value of this node is: 6left child is nullptr.right child is nullptr.value of this node is: 7left child is nullptr.right child is nullptr.Test2 begins:The preorder sequence is: 1 2 4 7 3 5 6 8The inorder sequence is: 4 7 2 1 5 3 8 6 value of this node is: 1value of its left child is: 2.value of its right child is: 3.value of this node is: 2value of its left child is: 4.right child is nullptr.value of this node is: 4left child is nullptr.value of its right child is: 7.value of this node is: 7left child is nullptr.right child is nullptr.value of this node is: 3value of its left child is: 5.value of its right child is: 6.value of this node is: 5left child is nullptr.right child is nullptr.value of this node is: 6value of its left child is: 8.right child is nullptr.value of this node is: 8left child is nullptr.right child is nullptr.Test3 begins:The preorder sequence is: 1 2 3 4 5The inorder sequence is: 5 4 3 2 1 value of this node is: 1value of its left child is: 2.right child is nullptr.value of this node is: 2value of its left child is: 3.right child is nullptr.value of this node is: 3value of its left child is: 4.right child is nullptr.value of this node is: 4value of its left child is: 5.right child is nullptr.value of this node is: 5left child is nullptr.right child is nullptr.Test4 begins:The preorder sequence is: 1 2 3 4 5The inorder sequence is: 1 2 3 4 5 value of this node is: 1left child is nullptr.value of its right child is: 2.value of this node is: 2left child is nullptr.value of its right child is: 3.value of this node is: 3left child is nullptr.value of its right child is: 4.value of this node is: 4left child is nullptr.value of its right child is: 5.value of this node is: 5left child is nullptr.right child is nullptr.Test5 begins:The preorder sequence is: 1The inorder sequence is: 1 value of this node is: 1left child is nullptr.right child is nullptr.Test6 begins:The preorder sequence is:The inorder sequence is: this node is nullptr.Test7: for unmatched input begins:The preorder sequence is: 1 2 4 5 3 6 7The inorder sequence is: 4 2 8 1 6 3 7Invalid input. 3. 头文件12345678910111213141516171819202122232425// 剑指offer // BinaryTree.h// chenyu// 2019_08_07#include &lt;vector&gt;struct BinaryTreeNode&#123; int m_nValue; BinaryTreeNode* m_pLeft; BinaryTreeNode* m_pRight;&#125;;/*__declspec( dllexport ) BinaryTreeNode* CreateBinaryTreeNode(int value);__declspec( dllexport ) void ConnectTreeNodes(BinaryTreeNode* pParent, BinaryTreeNode* pLeft, BinaryTreeNode* pRight);__declspec( dllexport ) void PrintTreeNode(const BinaryTreeNode* pNode);__declspec( dllexport ) void PrintTree(const BinaryTreeNode* pRoot);__declspec( dllexport ) void DestroyTree(BinaryTreeNode* pRoot);*/BinaryTreeNode* CreateBinaryTreeNode(int value);void ConnectTreeNodes(BinaryTreeNode* pParent, BinaryTreeNode* pLeft, BinaryTreeNode* pRight);void PrintTreeNode(const BinaryTreeNode* pNode);void PrintTree(const BinaryTreeNode* pRoot);void DestroyTree(BinaryTreeNode* pRoot); 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677// 剑指offer // BinaryTree.cpp// chenyu// 2019_08_07#include &quot;BinaryTree.h&quot;#include &lt;cstdio&gt;BinaryTreeNode* CreateBinaryTreeNode(int value)&#123; BinaryTreeNode* pNode = new BinaryTreeNode(); pNode-&gt;m_nValue = value; pNode-&gt;m_pLeft = nullptr; pNode-&gt;m_pRight = nullptr; return pNode;&#125;void ConnectTreeNodes(BinaryTreeNode* pParent, BinaryTreeNode* pLeft, BinaryTreeNode* pRight)&#123; if(pParent != nullptr) &#123; pParent-&gt;m_pLeft = pLeft; pParent-&gt;m_pRight = pRight; &#125;&#125;// 一个结点包括3部分，值域以及左右child的指针域// 此处打印，是打印一个完整的结点，包括其自身的值以及左右孩子的值void PrintTreeNode(const BinaryTreeNode* pNode)&#123; if(pNode != nullptr) &#123; printf(&quot;value of this node is: %d
&quot;, pNode-&gt;m_nValue); if(pNode-&gt;m_pLeft != nullptr) printf(&quot;value of its left child is: %d.
&quot;, pNode-&gt;m_pLeft-&gt;m_nValue); else printf(&quot;left child is nullptr.
&quot;); if(pNode-&gt;m_pRight != nullptr) printf(&quot;value of its right child is: %d.
&quot;, pNode-&gt;m_pRight-&gt;m_nValue); else printf(&quot;right child is nullptr.
&quot;); &#125; else printf(&quot;this node is nullptr.
&quot;); printf(&quot;
&quot;);&#125;void PrintTree(const BinaryTreeNode* pRoot)&#123; PrintTreeNode(pRoot); if(pRoot != nullptr) &#123; if(pRoot-&gt;m_pLeft != nullptr) PrintTree(pRoot-&gt;m_pLeft); if(pRoot-&gt;m_pRight != nullptr) PrintTree(pRoot-&gt;m_pRight); &#125;&#125;void DestroyTree(BinaryTreeNode* pRoot)&#123; if(pRoot != nullptr) &#123; BinaryTreeNode* pLeft = pRoot-&gt;m_pLeft; BinaryTreeNode* pRight = pRoot-&gt;m_pRight; delete pRoot; pRoot = nullptr; DestroyTree(pLeft); DestroyTree(pRight); &#125;&#125;

05_PrintListInReversedOrder1. 题目 从尾到头打印链表输入一个链表的头结点，从尾到头反过来打印出每个节点的值。链表结点定义如下：12345struct ListNode&#123; int m_nKey; ListNode* m_pNext;&#125; 2. 解析反转列表。输入链表头结点，从尾到头反过来打印每个节点的值。1-&gt;2-&gt;3-&gt;4 输出 4-&gt;3-&gt;2-&gt;1 3. 代码12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788899091929394// 剑指offer // 05_PrintListInReversedOrder.cpp// chenyu// 2019_08_04// 输入链表头结点，从尾到头反过来打印每个节点的值// 1-&gt;2-&gt;3-&gt;4 return 4-&gt;3-&gt;2-&gt;1//#include &quot;E:\Buffer\C++_code\CondingInterview_cy\Utilities\List.h&quot; #include &quot;.\Utilities\List.h&quot; // ..项目文件所在目录的上一级目录， . 是项目文件当前目录 #include &lt;stack&gt;#include &lt;cstdio&gt;void PrintListReversingly_Iteratively(ListNode *pHead)&#123; std::stack&lt;ListNode*&gt; nodes; ListNode *pNode = pHead; if(pNode == nullptr) return; while(pNode != nullptr) &#123; nodes.push(pNode); pNode = pNode-&gt;m_pNext; &#125; while(!nodes.empty()) // stack 非空 &#123; pNode = nodes.top(); // 返回栈顶元素，有返回值 printf(&quot;%d	&quot;, pNode-&gt;m_nValue); nodes.pop(); // 移除栈顶元素，无返回值 &#125;&#125;void PrintListReversingly_Recursively(ListNode *pHead)&#123; if(pHead != nullptr) &#123; if(pHead-&gt;m_pNext != nullptr) // 指向最后一个结点时开始打印 PrintListReversingly_Recursively(pHead-&gt;m_pNext); printf(&quot;%d	&quot;, pHead-&gt;m_nValue); &#125; &#125;/************ test ***********/void Print(ListNode *pHead)&#123; PrintList(pHead); PrintListReversingly_Iteratively(pHead); printf(&quot;
&quot;); PrintListReversingly_Recursively(pHead);&#125;// 功能测试（输入链表有多个结点）void Test1()&#123; printf(&quot;
Test1 begins.
&quot;); ListNode* pNode_1 = CreateListNode(1); ListNode* pNode_2 = CreateListNode(2); ListNode* pNode_3 = CreateListNode(3); ListNode* pNode_4 = CreateListNode(4); ConnectListNodes(pNode_1, pNode_2); ConnectListNodes(pNode_2, pNode_3); ConnectListNodes(pNode_3, pNode_4); //AddToTail(&amp;pNode_1, 2); // 也是 ok 的 //AddToTail(&amp;pNode_1, 3); //AddToTail(&amp;pNode_1, 4); Print(pNode_1); DestroyList(pNode_1);&#125;// 功能测试（输入链表只有一个结点）void Test2()&#123; printf(&quot;
Test2 begins.
&quot;); ListNode* pNode_1 = CreateListNode(1); Print(pNode_1); DestroyList(pNode_1); &#125;// 特殊输入测试（链表头结点指针为 NULL）void Test3()&#123; printf(&quot;
Test3 begins.
&quot;); Print(nullptr);&#125;int main()&#123; Test1(); Test2(); Test3(); return 0;&#125; output123456789101112131415161718PS E:\Buffer\C++_code\CondingInterview_cy&gt; .\05_PrintListInReversedOrder.exeTest1 begins.PrintList starts.1 2 3 4PrintList ends.4 3 2 14 3 2 1Test2 begins.PrintList starts.1PrintList ends.11Test3 begins.PrintList starts.PrintList ends. 4. 头文件12345678910111213141516171819202122232425262728293031// 剑指offer // List.h// chenyu// 2019_08_06//#ifndef LIST_H_//#define LIST_H_struct ListNode&#123; int m_nValue; ListNode *m_pNext;&#125;;__declspec( dllexport ) ListNode* CreateListNode(int value);__declspec( dllexport ) void ConnectListNodes(ListNode* pCurrent, ListNode* pNext);__declspec( dllexport ) void PrintListNode(ListNode* pNode);__declspec( dllexport ) void PrintList(ListNode* pHead);__declspec( dllexport ) void DestroyList(ListNode* pHead);__declspec( dllexport ) void AddToTail(ListNode** pHead, int value);__declspec( dllexport ) void RemoveNode(ListNode** pHead, int value);/*ListNode* CreateListNode(int value);void ConnectListNodes(ListNode* pCurrent, ListNode* pNext); // 连接两个结点void PrintListNode(ListNode* pNode); // 注意这里是 List Node，不是 Listvoid PrintList(ListNode* pHead);void DestroyList(ListNode* pHead);void AddToTail(ListNode** pHead, int value);void RemoveNode(ListNode** pHead, int value);*///#endif 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119// 剑指offer // List.cpp// chenyu// 2019_08_06#include &quot;List.h&quot;#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;// 创建链表结点ListNode* CreateListNode(int value)&#123; ListNode *pNode = new ListNode(); pNode-&gt;m_nValue = value; pNode-&gt;m_pNext = nullptr; return pNode;&#125;// 连接两个结点void ConnectListNodes(ListNode* pCurrent, ListNode* pNext) // 连接两个结点&#123; if(pCurrent == nullptr) &#123; printf(&quot;Error to connect two nodes.
&quot;); exit(1); // 一般，0 表示正常退出，其他表示非正常，在 stdlib 头文件里 &#125; pCurrent-&gt;m_pNext = pNext;&#125;// 打印结点值void PrintListNode(ListNode* pNode) // 注意这里是 List Node，不是 List&#123; if(pNode == nullptr) printf(&quot;The node is nullptr.
&quot;); else printf(&quot;The key in node is %d.
&quot;, pNode-&gt;m_nValue); &#125;// 打印链表void PrintList(ListNode* pHead) &#123; printf(&quot;PrintList starts.
&quot;); ListNode* pNode = pHead; // pNode 指针也指向 头为 pHead 的链表 while(pNode != nullptr) //while(pNode != nullptr &amp;&amp; pNode-&gt;m_pNest != nullptr) // by myself &#123; printf(&quot;%d	&quot;, pNode-&gt;m_nValue); //if(pNode-&gt;m_pNest != nullptr) // by myself, 最后指针指向链表最后一个结点 pNode = pNode-&gt;m_pNext; // 因为 pNode 也是一个指针，但是是临时的，所以可以不用加上一行 &#125; printf(&quot;
PrintList ends.
&quot;); &#125;// 销毁链表void DestroyList(ListNode* pHead)&#123; ListNode *pNode = pHead; while(pNode != nullptr) &#123; pHead = pHead-&gt;m_pNext; delete pNode; // 这里是 pNode pNode = pHead; &#125;&#125;// 单向链表末尾添加一个结点void AddToTail(ListNode** pHead, int value)&#123; ListNode *pNew = new ListNode(); pNew-&gt;m_nValue = value; pNew-&gt;m_pNext = nullptr; if(*pHead == nullptr) *pHead = pNew; else &#123; ListNode* pNode = *pHead; while(pNode-&gt;m_pNext != nullptr) &#123; pNode = pNode-&gt;m_pNext; &#125; pNode-&gt;m_pNext = pNew; &#125;&#125;// 在链表中找到第一个含有某值的结点并删除该结点void RemoveNode(ListNode** pHead, int value)&#123; if(*pHead == nullptr || pHead == nullptr) return; ListNode* pToBeDeleted = nullptr; if((*pHead)-&gt;m_nValue == value) &#123; pToBeDeleted = *pHead; *pHead = (*pHead)-&gt;m_pNext; &#125; else &#123; ListNode* pNode = *pHead; while (pNode-&gt;m_pNext != nullptr &amp;&amp; pNode-&gt;m_pNext-&gt;m_nValue != value) &#123; pNode = pNode-&gt;m_pNext; &#125; if(pNode-&gt;m_pNext != nullptr &amp;&amp; pNode-&gt;m_pNext-&gt;m_nValue == value) &#123; pToBeDeleted = pNode-&gt;m_pNext; pNode-&gt;m_pNext = pNode-&gt;m_pNext-&gt;m_pNext; &#125; &#125; if(pToBeDeleted != nullptr) &#123; delete pToBeDeleted; pToBeDeleted = nullptr; &#125;&#125;

7.1.1 题目编写一个程序，不断要求用户输入两个数，直到其中的一个为0。对于每两个数，程序将使用一个函数来计算它们的调和平均数，并将结果返回给 main()，而后者将报告结果。调和平均数指的是倒数平均值的倒数，计算公式如下：1调和平均数 = 2.0*x*y/(x+y) 7.1.2 代码12345678910111213141516171819202122232425#include &lt;iostream&gt;double har_ave(double x, double y);int main()&#123; using namespace std; double n,m; cout &lt;&lt; &quot;Enter double nums(0 to quit): &quot;; cin &gt;&gt; n &gt;&gt; m; while((n!=0)&amp;&amp;(m!=0)) &#123; cout &lt;&lt; &quot;The answer is: &quot; &lt;&lt; har_ave(n,m) &lt;&lt; endl; cout &lt;&lt; &quot;Enter double nums(0 to quit): &quot;; cin &gt;&gt; n &gt;&gt; m; &#125; cout &lt;&lt; &quot;Has the 0, quit&quot; &lt;&lt; endl; return 0;&#125;double har_ave(double x, double y)&#123; double ave = 2.0*x*y/(x+y); return ave;&#125; 7.1.3 运行结果12345678910PS E:\Buffer\C++_code&gt; g++ .	est.cpp -o test.exePS E:\Buffer\C++_code&gt; .	est.exeEnter double nums(0 to quit): 2 2The answer is: 2Enter double nums(0 to quit): 1 2The answer is: 1.33333Enter double nums(0 to quit): 2.2 2.2The answer is: 2.2Enter double nums(0 to quit): 0 1Has the 0, quit 7.2 略 7.3.1 题目下面是一个结构声明：12345678struct box &#123; char maker[40]; float height; float width; float length; float volume; &#125;; a. 编写一个函数，按值传递 box 的结构，并显示每个成员的值。b. 编写一个函数，传递 box 结构的地址，并将 volume 成员设置为其他三维长度的乘积。c. 编写一个使用这两个函数的简单程序。 7.3.2 代码12345678910111213141516171819202122232425262728293031323334353637#include &lt;iostream&gt;using namespace std;struct box&#123; char maker[40]; float height; float width; float length; float volume;&#125;;void value_return(box value);void addr_return(box * addr);int main()&#123; box box_test = &#123;&quot;chen&quot;, 1.1, 2.0, 1.1, 0.0&#125;; value_return(box_test); addr_return(&amp;box_test); value_return(box_test); return 0;&#125;void value_return(box value)&#123; cout &lt;&lt; &quot;***** This is value return: *****&quot; &lt;&lt; endl; cout &lt;&lt; &quot;maker: &quot; &lt;&lt; value.maker &lt;&lt; endl; cout &lt;&lt; &quot;height: &quot; &lt;&lt; value.height &lt;&lt; endl; cout &lt;&lt; &quot;width: &quot; &lt;&lt; value.width &lt;&lt; endl; cout &lt;&lt; &quot;length: &quot; &lt;&lt; value.length &lt;&lt; endl; cout &lt;&lt; &quot;volume: &quot; &lt;&lt; value.volume &lt;&lt; endl;&#125;void addr_return(box * addr)&#123; addr-&gt;volume = addr-&gt;height*addr-&gt;width*addr-&gt;length;&#125; 7.3.3 运行结果12345678910111213PS E:\Buffer\C++_code&gt; .	est.exe***** This is value return: *****maker: chenheight: 1.1width: 2length: 1.1volume: 0***** This is value return: *****maker: chenheight: 1.1width: 2length: 1.1volume: 2.42 7.4 略 7.5.1 题目定义一个递归函数，接受一个整数参数，并返回该参数的阶乘。前面讲过，3 的阶乘写作 3！，等于 3*2！，依此类推；而 0！被定义为1.通用的计算公式是，如果 n 大于 0，则1n!=n*(n-1) 在程序中对该函数进行测试，程序使用循环让用户输入不同的值，程序将报告这些值的阶乘。 7.5.2 代码1234567891011121314151617181920212223#include &lt;iostream&gt;long factorial(int n);int main()&#123; using namespace std; int x; cout &lt;&lt; &quot;Enter the num: &quot;; while(cin&gt;&gt;x) &#123; cout &lt;&lt; x &lt;&lt; &quot;! is &quot; &lt;&lt; factorial(x) &lt;&lt; endl; cout &lt;&lt; &quot;Enter the num: &quot;; &#125; return 0;&#125;long factorial(int n)&#123; if (n==0) return 1; else return n*factorial(n-1);&#125; 7.5.3 运行结果123456789101112PS E:\Buffer\C++_code&gt; .	est.exeEnter the num: 00! is 1Enter the num: 11! is 1Enter the num: 22! is 2Enter the num: 33! is 6Enter the num: 44! is 24Enter the num: q 7.6.1 题目编写一个程序，它将使用下列函数：Fill_array() 将一个 double 数组的名称和长度作为参数。它提示用户输入 double 值，并将这些值存储到数组中。当数组被填满或用户输入了非数字时，输入将停止，并返回实际输入了多少个数字。Show_array() 将一个 double 数组的名称和长度作为参数，并显示该数组的内容。Reverse_array() 将一个 double 数组的名称和长度作为参数，并将存储在数组中的值的顺序反转。程序将使用这些函数来填充数组，然后显示数组；反转数组，然后显示数组；反转数组中除第一个和最后一个元素之外的所有元素，然后显示数组。 7.6.2 代码1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556#include &lt;iostream&gt;using namespace std;const int len = 4;int Fill_array(double str[], int size);void Show_array(double str[], int n);void Reverse_array(double str[], int n);int main()&#123; double strs[len] = &#123;0.0&#125;; int real_size; real_size = Fill_array(strs, len); Show_array(strs, real_size+1); Reverse_array(strs, real_size+1); Show_array(strs, real_size+1); return 0;&#125;;int Fill_array(double str[], int size)&#123; double value; int num=0; for (int i=0; i&lt;size; ++i) &#123; cout &lt;&lt; &quot;Enter the value(double): &quot;; if(!(cin&gt;&gt;value)) &#123; cin.clear(); while (cin.get() != &apos;
&apos;) continue; cout &lt;&lt; &quot;Bad input; Please enter a number: &quot;; break; &#125; else str[num++] = value; &#125; return num-1;&#125;void Show_array(double str[], int n)&#123; for (int i=0; i&lt;n; ++i) cout &lt;&lt; str[i] &lt;&lt; &quot; &quot; &lt;&lt; endl;&#125;void Reverse_array(double str[], int n)&#123; for (int i=0; i&lt;n/2; ++i) &#123; double temp = str[i]; str[i] = str[n-i-1]; str[n-i-1] = temp; &#125; &#125; 7.6.3 运行结果12345678910111213141516171819PS E:\Buffer\C++_code&gt; .	est.exeEnter the value(double): 1.1Enter the value(double): cBad input; Please enter a number: 1.11.1PS E:\Buffer\C++_code&gt; .	est.exeEnter the value(double): 1.1Enter the value(double): 2.2Enter the value(double): 3.3Enter the value(double): 4.41.12.23.34.44.43.32.21.1 7.7.1 题目修改程序清单 7.7 中的 3 个数组处理函数，使之使用两个指针参数来表示区间。fill_array() 函数不返回实际读取了多少个数字，而是返回一个指针，该指针指向最后被填充的位置；其他的函数可以将该指针作为第二个参数，以标识数据结尾。 7.7.2 代码1234567891011121314151617int main()&#123; using namespace std; const int Max=5; double arr[Max]; int * arr_end = fill_array(arr, Max); show_array(arr, arr_end); if (arr_end != arr) &#123; ... revalue(factor, arr, arr_end); show(arr, arr_end); &#125; return 0;&#125; 7.8.1 题目在不使用 array 类的情况下完成程序清单 7.15 所做的工作。编写两个这样的版本：a. 使用 const char 数组存储表示季度名称的字符串，并使用 double 数组存储开支。b. 使用 const char 数组存储表示季度名称的字符串，并使用一个结构，该结构只有一个成员——一个用于存储开支的 double 数组。这种设计与使用 array 类的基本设计类似。 7.8.2 代码12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182a#include &lt;iostream&gt;using namespace std;const int Seasons = 4;const char* Snames[Seasons] = &#123;&quot;Spring&quot;, &quot;Summer&quot;, &quot;Fall&quot;, &quot;Winter&quot;&#125;;void fill(double* array);void show(double *array);int main()&#123; double expenses[Seasons]; fill(expenses); show(expenses); return 0;&#125;void fill(double *array)&#123; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; &quot;Enter &quot; &lt;&lt; Snames[i] &lt;&lt; &quot;expenses: &quot;; cin &gt;&gt; array[i]; &#125;&#125;void show(double *array)&#123; double total = 0.0; cout &lt;&lt; &quot;
EXPENSES
&quot;; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; Snames[i] &lt;&lt; &quot;: $&quot; &lt;&lt; array[i] &lt;&lt;endl; total += array[i]; &#125; cout &lt;&lt; &quot;Total expenses: $&quot; &lt;&lt; total &lt;&lt; endl;&#125;b#include &lt;iostream&gt;using namespace std;const int Seasons = 4;const char* Snames[Seasons] = &#123;&quot;Spring&quot;, &quot;Summer&quot;, &quot;Fall&quot;, &quot;Winter&quot;&#125;;struct dollar&#123; double expenses[Seasons];&#125;;void fill(dollar * array);void show(dollar * array);int main()&#123; dollar pay; fill(&amp;pay); show(&amp;pay); return 0;&#125;void fill(dollar *array)&#123; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; &quot;Enter &quot; &lt;&lt; Snames[i] &lt;&lt; &quot;expenses: &quot;; cin &gt;&gt; array-&gt;expenses[i]; &#125;&#125;void show(dollar *array)&#123; double total = 0.0; cout &lt;&lt; &quot;
EXPENSES
&quot;; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; Snames[i] &lt;&lt; &quot;: $&quot; &lt;&lt; array-&gt;expenses[i] &lt;&lt;endl; total += array-&gt;expenses[i]; &#125; cout &lt;&lt; &quot;Total expenses: $&quot; &lt;&lt; total &lt;&lt; endl;&#125; 7.8.3 运行结果1234567891011121314a bEnter Summerexpenses: PS E:\Buffer\C++_code&gt; .	est.exeEnter Springexpenses: 212Enter Summerexpenses: 256Enter Fallexpenses: 208Enter Winterexpenses: 244EXPENSESSpring: $212Summer: $256Fall: $208Winter: $244Total expenses: $920 7.9.1 题目太长了，，加油！ 7.9.2 代码12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576#include &lt;iostream&gt;#include &lt;cstring&gt;using namespace std;const int SLEN = 30;struct student&#123; char fullname[SLEN]; char hobby[SLEN]; int ooplevel;&#125;;int getinfo(student pa[], int n)&#123; int real_num=0; for(int i=0; i&lt;n; i++) &#123; cout &lt;&lt; &quot;Enter the student&apos;s name: &quot;; cin.getline(pa[i].fullname, SLEN); // if string type, getline(cin, pa[i].fullname) if(!strlen(pa[i].fullname)) break; cout &lt;&lt; &quot;Enter the student&apos;s hobby: &quot;; cin.getline(pa[i].hobby, SLEN); cout &lt;&lt; &quot;Enter the student&apos;s ooplevel: &quot;; (cin &gt;&gt; pa[i].ooplevel).get(); real_num++; &#125; return real_num;&#125;void display1(student st)&#123; cout &lt;&lt; &quot;name: &quot; &lt;&lt; st.fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; st.hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; st.ooplevel &lt;&lt; endl; &#125;void display2(const student *st)&#123; cout &lt;&lt; &quot;name: &quot; &lt;&lt; st-&gt;fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; st-&gt;hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; st-&gt;ooplevel &lt;&lt; endl;&#125;void display3(const student pa[],int n)&#123; for(int i = 0; i &lt; n; i++) &#123; cout &lt;&lt; &quot;info #&quot; &lt;&lt; i &lt;&lt; endl; cout &lt;&lt; &quot;name: &quot; &lt;&lt; (pa + i)-&gt;fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; (pa + i)-&gt;hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; (pa + i)-&gt;ooplevel &lt;&lt; endl; &#125;&#125;int main()&#123; cout &lt;&lt; &quot;enter class size: &quot;; int class_size; cin &gt;&gt; class_size; while(cin.get()!=&apos;
&apos;) continue; student *ptr_stu = new student[class_size]; int entered = getinfo(ptr_stu,class_size); cout &lt;&lt; &quot;
