&quot;; for(int i=0;i&lt;entered;i++) &#123; display1(ptr_stu[i]); display2(&amp;ptr_stu[i]); &#125; cout &lt;&lt; &quot;

&quot;; display3(ptr_stu,entered); delete [] ptr_stu; cout &lt;&lt; &quot;Done!&quot;; return 0;&#125; 7.9.3 运行结果12345678910111213141516171819202122232425262728PS E:\Buffer\C++_code&gt; .	est.exeenter class size: 1Enter the student&apos;s name: diplay1 and 2Done!PS E:\Buffer\C++_code&gt; .	est.exeenter class size: 1Enter the student&apos;s name: jac kEnter the student&apos;s hobby: pla yEnter the student&apos;s ooplevel: 12 diplay1 and 2name: jac khobby: pla yooplevel: 12name: jac khobby: pla yooplevel: 12info #0name: jac khobby: pla yooplevel: 12Done! 7.10.1 题目设计一个名为 calculate() 的函数，它接受两个 double 值和一个指向函数的指针，而被指向的函数接受两个 double 参数，并返回一个 double 值。calculate() 函数的类型也是 double，并返回被指向的函数使用 calculate() 的两个 double 参数计算得到的值。例如，假设 add() 函数的定义如下：1234double add(double x, double y)&#123; return x + y;&#125; 则用下述代码中的函数调用将导致 calculate() 把 2.5 和 10.4 传递给 add() 函数，并返回 add() 的返回值 (12.9):1double q = calculate(2.5, 10.4, add); 请编写一个程序，它调用上述两个函数和至少另一个与 add() 类似的函数。该程序使用循环来让用户成对的输入数字。对于每对数字，程序都使用 calculate() 来调用 add() 和至少一个其他的函数。如果读者爱冒险，可以尝试创建一个指针数组，其中的指针指向 add() 样式的函数，并编写一个循环，使用这些指针连续让 calculate() 调用这些函数。提示：下面是声明这种指针数组的方式，其中包含三个指针：1double (*pf[3])(double, double)； 可以采用数组初始化语法，并将函数名作为地址来初始化这样的数组。 7.10.2 代码1234567891011121314151617181920212223242526272829303132333435363738#include &lt;iostream&gt;double calculate(double x, double y, double (*pt)(double, double));double add(double x, double y);double reduce(double x, double y);int main()&#123; using namespace std; cout &lt;&lt; &quot;Enter two nums: &quot; &lt;&lt; endl; double n,m; cin &gt;&gt; n &gt;&gt; m; cout &lt;&lt; &quot;add value: &quot; &lt;&lt; calculate(n, m, add) &lt;&lt; endl; cout &lt;&lt; &quot;reduce value: &quot; &lt;&lt; calculate(n, m, reduce) &lt;&lt; endl; double (*pf[2])(double, double) = &#123;add, reduce&#125;; // 函数指针数组 cout &lt;&lt; &quot;an array of 2 function pointers: &quot; &lt;&lt; endl; for (int i=0; i&lt;2; i++) &#123; cout &lt;&lt; calculate(n, m, pf[i]) &lt;&lt; endl; &#125; return 0;&#125;double calculate(double x, double y, double (*pt)(double, double))&#123; return pt(x, y);&#125;double add(double x, double y)&#123; return x+y;&#125;double reduce(double x, double y)&#123; return x-y;&#125; 7.10.3 运行结果12345678PS E:\Buffer\C++_code&gt; .	est.exeEnter two nums:1.1 2.2add value: 3.3reduce value: -1.1an array of 2 function pointers:3.3-1.1

基于FPGA的任意波形发生器（Easy版）【2017.04.13】Chenyu 实现功能： 要求用FPGA做一款波形、幅值、频率可调，且频率可通过开发板的数码管显示硬件平台： Altera 黑金 AX301 Cyclone ⅣE EP4CE6F17C8 R-2R电阻网络（DAC模块）软件平台： QuartusⅡ Guagle/matlab 思路： 用C或者matlab等软件生成mif文件；将mif文件导入FPGA的ROM；对各个模块编写程序；模块例化5.DAC 一、生成MIF文件mif文件就是存储器初始化文件，即memory initialization file，用来配置RAM或ROM中的数据。 1.1 利用Quartus自带的mif编译器优：对小容量的RAM、ROM可以快速方便的完成mif文件的编辑工作，不需要第三方软件编辑；缺：数据量过大时，不推荐使用使用方法：【File】_&gt;【New】 _&gt;【Memory Initialization file】 Number of words：可寻址的存储单元数，对于8bit地址线，此处选择256；words size：存储单元宽度，8bit右击左侧地址值可改变地址和数据的显示格式；表中任意数据的地制值=列值+行值（图中蓝色单元的地址为32+3=35） 1.2 利用mif软件生成本次任务中我采用的是Guagle。优：方便导出mif文件，尤其是数据量比较大时。缺：此款软件可以自动设置的波形只有：方波、正弦波、锯齿波、三角波。不过这个软件支持手绘图形。使用方法： 更改设定波形和变量可以对相应参数进行配置。 1.3 利用高级语言C语言或matlab语言来生成相应的mif文件C语言生成正弦波的数据波形（代码来源于网络）123456789101112131415161718192021222324252627282930313233343536373839404142434445#include &lt;stdio.h&gt;#include &lt;math.h&gt;#define PI 3.141592#define DEPTH 128 /*数据深度，即存储单元的个数*/#define WIDTH 8 /*存储单元的宽度*/int main(void)&#123; int i,temp; float s; FILE *fp; fp = fopen(&quot;TestMif.mif&quot;,&quot;w&quot;); /*文件名随意，但扩展名必须为.mif*/ if(NULL==fp) printf(&quot;Can not creat file!
&quot;); else &#123; printf(&quot;File created successfully!
&quot;); /* * 生成文件头：注意不要忘了“;” */ fprintf(fp,&quot;DEPTH = %d;
&quot;,DEPTH); fprintf(fp,&quot;WIDTH = %d;
&quot;,WIDTH); fprintf(fp,&quot;ADDRESS_RADIX = HEX;
&quot;); fprintf(fp,&quot;DATA_RADIX = HEX;
&quot;); fprintf(fp,&quot;CONTENT
&quot;); fprintf(fp,&quot;BEGIN
&quot;); /* * 以十六进制输出地址和数据 */ for(i=0;i&lt;DEPTH;i++) &#123; /*周期为128个点的正弦波*/ s = sin(PI*i/64); /*将-1～1之间的正弦波的值扩展到0-255之间*/ temp = (int)((s+1)*255/2); /*以十六进制输出地址和数据*/ fprintf(fp,&quot;%x	:	%x;
&quot;,i,temp); &#125;//end for fprintf(fp,&quot;END;
&quot;); fclose(fp); &#125;&#125; matlab1234567891011121314151617depth = 512; %存储器的单元数widths = 8; %数据宽度为8位%N = 0:511;%s =round(127*sin(2*pi*N/512)+128); %计算0 ~2*pi之间的sinֵfidc = fopen(&apos;sin.mif&apos;,&apos;wt&apos;);fprintf(fidc , &apos;depth = %d;
&apos;,depth);fprintf(fidc, &apos;width = %d;
&apos;,widths);fprintf(fidc, &apos;address_radix = UNS;
&apos;);fprintf(fidc,&apos;data_radix = UNS;
&apos;);fprintf(fidc,&apos;content begin
&apos;);for(x = 1 : depth) fprintf(fidc,&apos;%d:%d;
&apos;,x-1,round(127*sin(2*pi*(x-1)/512)+128)); endfprintf(fidc, &apos;end;&apos;);fclose(fidc); matlab（代码来源于陈强胜）1234567891011121314151617181920%mif生成 xt为输入WIDTH=8;DEPTH=256xt2=floor(xt);%xt取整xt2=xt2+128.*ones(1,256);%将数据加128fp=fopen(&apos;sin.txt&apos;,&apos;w&apos;);fprintf(fp,&apos;WIDTH=%d;
